script.code:
//----------------Inicializo variables -------------------//


//Variable interna
var Info_Windowact=false;
var Markeract=false;
var Markeractdc;
var Markers= new Array();
var Rutas= new Array();
var Pos_origen;
var Pos_destination;
var WayPoints = new Array();

var google = webMI.rootWindow.google; //Clase Principal
var map; //Variable donde va a vivir el mapa
var m,n;

//Obtener el nombre en formato string del objeto base, haciendo una query al webMI 
	var name = webMI.query.base;
	//Parte de la función addOnload
	var id = "";
	var value = true;


var infowindow;


const path_circulo = "M 4 1.5 A 2.5 2.5 90 1 0 4 6.5 A 2.5 2.5 90 0 0 4 1.5 Z";
const path_triangulo = "M 3 0.9383 L 5.3878 5.0625 H 0.6122 L 3 0.9383 Z";

/*var symbol=   {
				path: path_circulo,
				fillColor: "green",
				fillOpacity: 1,
				strokeWeight: 0,
				rotation: 0,
				scale: 3,
				anchor: new google.maps.Point(0, 0),
			  };

			  symbol.path = path_triangulo;
			  symbol.fillColor = "blue";*/

const symbolSofrel =  {
    path: path_triangulo,
    fillColor: "blue",
    fillOpacity: 1,
    strokeWeight: 0,
    rotation: 0,
    scale: 3,
    anchor: new google.maps.Point(0, 0),
  };
const symbolOK =   {
    path: path_circulo,
    fillColor: "green",
    fillOpacity: 1,
    strokeWeight: 0,
    rotation: 0,
    scale: 3,
    anchor: new google.maps.Point(0, 0),
  };
const symbolNoCom =  {
    path: path_circulo,
    fillColor: "red",
    fillOpacity: 1,
    strokeWeight: 0,
    rotation: 0,
    scale: 3,
    anchor: new google.maps.Point(0, 0),
  };
const symbolIdle =  {
    path: path_circulo,
    fillColor: "#7c1536",
    fillOpacity: 1,
    strokeWeight: 0,
    rotation: 0,
    scale: 3,
    anchor: new google.maps.Point(0, 0),
  };
const symbolWriteError =  {
    path: path_circulo,
    fillColor: "#8b3db8",
    fillOpacity: 1,
    strokeWeight: 0,
    rotation: 0,
    scale: 3,
    anchor: new google.maps.Point(0, 0),
  };
const symbolBadDevice =  {
    path: path_circulo,
    fillColor: "#b98f2d",
    fillOpacity: 1,
    strokeWeight: 0,
    rotation: 0,
    scale: 3,
    anchor: new google.maps.Point(0, 0),
  };
 const symbolUndefined =  {
    path: path_circulo,
    fillColor: "gray",
    fillOpacity: 1,
    strokeWeight: 0,
    rotation: 0,
    scale: 3,
    anchor: new google.maps.Point(0, 0),
  };
   const symbolBlack =  {
    path: path_circulo,
    fillColor: "black",
    fillOpacity: 0.6,
    strokeWeight: 0,
    rotation: 0,
    scale: 3,
    anchor: new google.maps.Point(0, 0),
  };


//----------------Ejecución -------------------//



//Determinación del dispositivo
var infoCliente;
infoCliente = new webMI.getClientInfo();

webMI.addOnload(function() {


	//Opciones del mapa
	var myOptions = {
		zoom: 10,
		mapTypeId: google.maps.MapTypeId.roadmap,
		styles: [ 
					{ 
					  "featureType": "poi", 
					  "stylers": [ 
						{ "visibility": "off" } 
					  ] 
					} 
				  ] 
	};


	//Inicializo el mapa
	map = new google.maps.Map(document.getElementById("mapa"), myOptions);




	// Instantiate an info window to hold step text.
	const stepDisplay = new google.maps.InfoWindow();

	//-------Inicializo Marcadores

	circuito_s.forEach(([position,title,object,order,type],i) =>{

		const marker = new google.maps.Marker({
			position, 
			map,
			icon: symbolBlack,
			title: ` ${title}`,
			optimized: false,
		});

		webMI.data.subscribe(object + ".connectivity", function(e) {
			var valor = e.value;
			var status = e.status;

			switch (status) {
		case 0:
			if (valor == true)
				marker.setIcon(symbolOK);
			else
				marker.setIcon(symbolNoCom);
			break;
		case undefined:
			if (type == "LS42" ||type == "LSP"){
			marker.setIcon(symbolSofrel);
			}else {
			marker.setIcon(symbolUndefined);
			}
			break;
		case 2156593152:
			marker.setIcon(symbolBadDevice);
			break;
		case 2150694912:
			marker.setIcon(symbolNoCom);
			break;
		case 2150760448:
			marker.setIcon(symbolIdle);
			break;
		case 1083179008:
			marker.setIcon(symbolBlack);
			break;
		default:
			marker.setIcon(symbolBlack);
			break;
			}
		});	
		marker.setMap(map);
		//Agrego marcador a lista de marcadores
		Markers.push(marker);

		//-------Listener de Marcadores

		//DOBLECLICK (Fija Carcamo)
		google.maps.event.addListener(marker,'dblclick',function(event) {
			map.panTo(this.getPosition());
			map.setZoom(15);

			switch(type) {
			case "carcamoAP":
				webMI.display.openWindow({display:"SYSTEM.DISPLAYS.Sectorizacion.Grafico_Sectorizacion_Tanque" ,
				extern:false,height:400,menubar:false,modal:false,movable:true,resizable:true,scrollbars:false,status:false,
				title:title,toolbar:false,x:0,y:480,width:1150,query:{base:object}});
				break;
			case "LSP":
				webMI.display.openWindow({display:"SYSTEM.DISPLAYS.Sectorizacion.Grafico_Sectorizacion_Solo_Presion" ,
				extern:false,height:400,menubar:false,modal:false,movable:true,resizable:true,scrollbars:false,status:false,
				title:title,toolbar:false,x:0,y:480,width:600,query:{base:object}});
				break;
			case "LS42":
				webMI.display.openWindow({display:"SYSTEM.DISPLAYS.Sectorizacion.Grafico_Sectorizacion" ,
				extern:false,height:400,menubar:false,modal:false,movable:true,resizable:true,scrollbars:false,status:false,
				title:title,toolbar:false,x:0,y:480,width:1150,query:{base:object}});
				break;
			default:
			break;
						}


			Markeract=true;
			Markeractdc=marker;
			Pos_origen=position;


			//Limpio
			Elimina_Ruta(Rutas);

		});
	/*	map.addListener("zoom_changed", () => {
    infowindow.setContent("Zoom: " + map.getZoom());
  });*/

		var susID = null;
		//CLICK (Abre Infowindow)
		google.maps.event.addListener(marker,'click',function(event) {	

            webMI.data.unsubscribe(susID);

			susID = null;



			infowindow = new google.maps.InfoWindow();
			//Abro marcador
			infowindow.open(marker.getMap,marker);


			if (type == 'LS42' || type == 'LSP'){
				//Defino que objeto va a ser el seleccionado para mostrar su información

			susID = webMI.data.subscribe( object +".HValuePresion",
				function(e){
					infowindow.setContent(
						'<div id="content">' +
                            '<h2 id="firstHeading" class="firstHeading">'+title+'</h2>' +
                            '<h3>'+'Presión: '+ e.value.toFixed(2) +' kg/cm2</h>' +
                         '</div>');
					}
				);
			} else {
			//Defino que objeto va a ser el seleccionado para mostrar su información
			susID = webMI.data.subscribe( object +".pressure",
				function(e){
					infowindow.setContent(
					'<div id="content">' +
                            '<h1 id="firstHeading" class="firstHeading">'+title+'</h1>' +
                            '<h2>'+'Presión: '+ e.value.toFixed(2) +' kg/cm2</h2>' +
                         '</div>');
					}
				);
			}

			setTimeout(function() {
              infowindow.close();             
                webMI.data.unsubscribe(susID);
            }, 3000);
					console.log(susID);	
		});	

		//MOUSEOVER
		google.maps.event.addListener(marker, "mouseover", function(event){
		});		
	});	
		fitMarkers();	
});

function fitMarkers() {
            const bounds = new google.maps.LatLngBounds();
            Markers.splice(0,4);
            Markers.forEach(marker => {
                bounds.extend(marker.getPosition());
            });

            map.fitBounds(bounds);
        }
